import logging
import azure.functions as func

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Payment notification received')

    # Process payment notification data from the request body
    req_body = req.get_json()

    if not req_body:
        return func.HttpResponse(
            status_code=400,
            body='Missing required payment notification data'
        )

    payment_data = {
        'id': req_body['id'],
        'amount': req_body['amount'],
        'currency': req_body['currency']
    }

    # Save processed payment data to database or queue
    logging.info('Processed payment data: %s', str(payment_data))

    return func.HttpResponse(
        status_code=200,
        body='Payment notification received and processed successfully'
    )